<div class="page-title"><div><h1>Services</h1><p class="muted">Manage service catalog and fees.</p></div><button class="btn btn-primary" data-bs-toggle="modal" data-bs-target="#serviceModal" onclick="serviceForm.reset();service_id.value=''"><i class="bi bi-plus-lg me-2"></i>Add Service</button></div>
