<script>
document.addEventListener('DOMContentLoaded',()=>{bindAjaxForm('.ajax-reload');document.querySelectorAll('.edit-service').forEach(b=>b.onclick=()=>{const d=JSON.parse(b.dataset.row);service_id.value=d.id;for(const k in d){const el=serviceForm.elements[k];if(el)el.value=d[k]??'';}new bootstrap.Modal('#serviceModal').show();});document.querySelectorAll('.delete-service').forEach(b=>b.onclick=()=>Swal.fire({title:'Mark inactive?',showCancelButton:true}).then(async r=>{if(r.isConfirmed){const fd=new FormData();fd.append('csrf_token','<?= e(csrf_token()) ?>');fd.append('id',b.dataset.id);const data=await safeFetch('ajax/service-delete.php',{method:'POST',body:fd});if(data.success)location.reload();}}));});
</script>
